private actor LiveAudioReceiveTestRecorder {
    private let ackDelayNanoseconds: UInt64
    private let summaryDelayNanoseconds: UInt64
    private let dropDelayNanoseconds: UInt64
    private(set) var ackCount = 0
    private(set) var fallbackCount = 0
    private(set) var summaries: [LiveAudioReceiveDiagnosticSummary] = []
    private(set) var drops: [LiveAudioReceiveDropDiagnostic] = []
    private(set) var readinessDiagnostics: [LiveAudioReceivePlaybackReadinessDiagnostic] = []

    init(
        ackDelayNanoseconds: UInt64 = 0,
        summaryDelayNanoseconds: UInt64 = 0,
        dropDelayNanoseconds: UInt64 = 0
    ) {
        self.ackDelayNanoseconds = ackDelayNanoseconds
        self.summaryDelayNanoseconds = summaryDelayNanoseconds
        self.dropDelayNanoseconds = dropDelayNanoseconds
    }

    func recordAck(_: IncomingAudioIngressAcceptedPacket) async {
        ackCount += 1
        await delayIfNeeded(ackDelayNanoseconds)
    }

    func recordFallback() {
        fallbackCount += 1
    }

    func recordSummary(_ summary: LiveAudioReceiveDiagnosticSummary) async {
        summaries.append(summary)
        await delayIfNeeded(summaryDelayNanoseconds)
    }

    func recordDrop(_ drop: LiveAudioReceiveDropDiagnostic) async {
        drops.append(drop)
        await delayIfNeeded(dropDelayNanoseconds)
    }

    func recordReadinessDiagnostic(
        _ diagnostic: LiveAudioReceivePlaybackReadinessDiagnostic
    ) {
        readinessDiagnostics.append(diagnostic)
    }

    private func delayIfNeeded(_ nanoseconds: UInt64) async {
        guard nanoseconds > 0 else { return }
        try? await Task.sleep(nanoseconds: nanoseconds)
    }

    func waitForAckCount(
        _ expectedCount: Int,
        timeoutNanoseconds: UInt64 = 1_000_000_000
    ) async -> Bool {
        let deadline = DispatchTime.now().uptimeNanoseconds + timeoutNanoseconds
        while DispatchTime.now().uptimeNanoseconds < deadline {
            if ackCount >= expectedCount {
                return true
            }
            try? await Task.sleep(nanoseconds: 10_000_000)
        }
        return ackCount >= expectedCount
    }

    func waitForDropCount(
        _ expectedCount: Int,
        timeoutNanoseconds: UInt64 = 1_000_000_000
    ) async -> Bool {
        let deadline = DispatchTime.now().uptimeNanoseconds + timeoutNanoseconds
        while DispatchTime.now().uptimeNanoseconds < deadline {
            if drops.count >= expectedCount {
                return true
            }
            try? await Task.sleep(nanoseconds: 10_000_000)
        }
        return drops.count >= expectedCount
    }

    func waitForSummaryCount(
        _ expectedCount: Int,
        timeoutNanoseconds: UInt64 = 1_000_000_000
    ) async -> Bool {
        let deadline = DispatchTime.now().uptimeNanoseconds + timeoutNanoseconds
        while DispatchTime.now().uptimeNanoseconds < deadline {
            if summaries.count >= expectedCount {
                return true
            }
            try? await Task.sleep(nanoseconds: 10_000_000)
        }
        return summaries.count >= expectedCount
    }

    func waitForReadinessDiagnosticCount(
        _ expectedCount: Int,
        timeoutNanoseconds: UInt64 = 1_000_000_000
    ) async -> Bool {
        let deadline = DispatchTime.now().uptimeNanoseconds + timeoutNanoseconds
        while DispatchTime.now().uptimeNanoseconds < deadline {
            if readinessDiagnostics.count >= expectedCount {
                return true
            }
            try? await Task.sleep(nanoseconds: 10_000_000)
        }
        return readinessDiagnostics.count >= expectedCount
    }
}

private final class LockedTestCounter: @unchecked Sendable {
    private let lock = NSLock()
    private var value = 0

    func incrementAndGet() -> Int {
        lock.withLock {
            value += 1
            return value
        }
    }

    var current: Int {
        lock.withLock { value }
    }
}

private final class LockedTestFlag: @unchecked Sendable {
    private let lock = NSLock()
    private var value: Bool

    init(_ value: Bool = false) {
        self.value = value
    }

    func set(_ newValue: Bool) {
        lock.withLock {
            value = newValue
        }
    }

    var current: Bool {
        lock.withLock { value }
    }
}

@MainActor
struct ConnectionTests {
    nonisolated private static func blockCurrentThreadForTesting(milliseconds: UInt64) {
        Thread.sleep(forTimeInterval: Double(milliseconds) / 1_000)
    }

    @discardableResult
    private func markPTTLocalTransmitAudioSessionActive(
        _ viewModel: PTTViewModel,
        channelUUID: UUID,
        target: TransmitTarget
    ) -> PTTAudioSessionEpoch {
        viewModel.isPTTAudioSessionActive = true
        return viewModel.pttAudioSessionRuntime.activate(
            owner: .localTransmit(
                channelUUID: channelUUID,
                contactID: target.contactID,
                channelID: target.channelID,
                transmitID: target.transmitID ?? "local-\(target.channelID)"
            )
        )
    }

    @discardableResult
    private func markPTTPendingLocalTransmitAudioSessionActive(
        _ viewModel: PTTViewModel,
        request: TransmitRequestContext,
        channelUUID: UUID
    ) -> PTTAudioSessionEpoch {
        viewModel.isPTTAudioSessionActive = true
        return viewModel.pttAudioSessionRuntime.activate(
            owner: .pendingLocalTransmit(
                channelUUID: channelUUID,
                contactID: request.contactID,
                channelID: request.backendChannelID
            )
        )
    }

    @Test func engineJoinedConversationCanRepresentMissingPeerDeviceWithoutSyntheticID() {
        let viewModel = PTTViewModel()
        let contactID = UUID()
        let contact = Contact(
            id: contactID,
            name: "Blake",
            handle: "@blake",
            isOnline: true,
            channelId: UUID(),
            backendChannelId: "channel-a-b",
            remoteUserId: "remote-user"
        )
        viewModel.contacts = [contact]
        viewModel.selectedContactId = contactID
        viewModel.seedEngineJoinedConversationForTesting(contactID: contactID)
        viewModel.backendSyncCoordinator.send(
            .channelStateUpdated(
                contactID: contactID,
                channelState: makeChannelState(
                    status: .waitingForPeer,
                    canTransmit: false,
                    peerDeviceConnected: false
                )
            )
        )

        viewModel.syncEngineJoinedConversation(contactID: contactID, reason: "test")
        viewModel.syncEngineBeginTalkIntent(reason: "test")

        if case .joined(let joined) = viewModel.engineSnapshot.conversation {
            #expect(joined.peerDeviceID == nil)
            #expect(joined.peerDevice == .pending(.waitingForPeerDevice))
            #expect(joined.receiverAddressability == .unavailable(.peerDeviceUnavailable))
            #expect(joined.readiness == .pending(.waitingForPeerDevice))
        } else {
            Issue.record("expected joined engine Conversation with pending peer device")
        }
        #expect(viewModel.engineSnapshot.transmit == .failed(
            TransmitFailure(
                conversation: viewModel.engineSnapshot.conversation.joinedEvidence,
                reason: .receiverNotAddressable(.peerDeviceUnavailable)
            )
        ))
    }

    @Test func backendWakeCapabilityFeedsEngineAddressableConversationWithoutForegroundPeerDevice() {
        let viewModel = PTTViewModel()
        let contactID = UUID()
        let contact = Contact(
            id: contactID,
            name: "Blake",
            handle: "@blake",
            isOnline: true,
            channelId: UUID(),
            backendChannelId: "channel-a-b",
            remoteUserId: "remote-user"
        )
        viewModel.contacts = [contact]
        viewModel.selectedContactId = contactID
        viewModel.seedEngineJoinedConversationForTesting(contactID: contactID)
        viewModel.backendSyncCoordinator.send(
            .channelStateUpdated(
                contactID: contactID,
                channelState: makeChannelState(
                    status: .ready,
                    canTransmit: true,
                    peerDeviceConnected: false
                )
            )
        )
        viewModel.backendSyncCoordinator.send(
            .channelReadinessUpdated(
                contactID: contactID,
                readiness: makeChannelReadiness(
                    status: .ready,
                    remoteWakeCapability: .wakeCapable(targetDeviceId: "wake-peer-device"),
                    peerTargetDeviceId: nil
                )
            )
        )

        viewModel.syncEngineJoinedConversation(contactID: contactID, reason: "test")

        if case .joined(let joined) = viewModel.engineSnapshot.conversation {
            #expect(joined.peerDevice == .pending(.waitingForPeerDevice))
            if case .wakeCapable(let evidence) = joined.receiverAddressability {
                #expect(evidence.channelID.rawValue == "channel-a-b")
                #expect(evidence.deviceID.rawValue == "wake-peer-device")
            } else {
                Issue.record("expected wake-capable receiver addressability")
            }
            #expect(joined.readiness != .pending(.waitingForPeerDevice))
        } else {
            Issue.record("expected joined engine Conversation with wake-capable receiver addressability")
        }
        #expect(viewModel.engineSnapshot.localTalkCapability != .blocked(.receiverNotAddressable(.peerDeviceUnavailable)))
    }

    @Test func mediaEndToEndEncryptionRoundTripsTransportPayload() throws {
        let senderPrivateKey = Curve25519.KeyAgreement.PrivateKey()
        let receiverPrivateKey = Curve25519.KeyAgreement.PrivateKey()
        let senderSharedSecret = try senderPrivateKey.sharedSecretFromKeyAgreement(with: receiverPrivateKey.publicKey)
        let receiverSharedSecret = try receiverPrivateKey.sharedSecretFromKeyAgreement(with: senderPrivateKey.publicKey)
        let context = MediaEncryptionContext(
            channelID: "channel-1",
            sessionID: "session-1",
            senderDeviceID: "device-a",
            receiverDeviceID: "device-b"
        )
        let senderKey = MediaEndToEndEncryption.deriveSymmetricKey(
            from: senderSharedSecret,
            context: context
        )
        let receiverKey = MediaEndToEndEncryption.deriveSymmetricKey(
            from: receiverSharedSecret,
            context: context
        )
        let payload = Data("pcm-audio-payload".utf8).base64EncodedString()

        let encrypted = try MediaEndToEndEncryption.sealTransportPayload(
            payload,
            using: senderKey,
            keyID: "key-1",
            sequenceNumber: 42,
            context: context
        )

        #expect(!encrypted.contains(payload))
        #expect(
            try MediaEndToEndEncryption.openTransportPayload(
                encrypted,
                using: receiverKey,
                context: context
            ) == payload
        )
    }

    @MainActor
    @Test func duplicatePlaintextAudioAcrossStandbyTransportsIsDropped() async {
        let viewModel = PTTViewModel()
        let contactID = UUID()
        let mediaSession = RecordingMediaSession()
        viewModel.applicationStateOverride = .active
        viewModel.contacts = [
            Contact(
                id: contactID,
                name: "Blake",
                handle: "@blake",
                isOnline: true,
                channelId: UUID(),
                backendChannelId: "channel-1",
                remoteUserId: "peer-user"
            )
        ]
        viewModel.selectedContactId = contactID
        viewModel.seedEngineJoinedConversationForTesting(contactID: contactID)
        viewModel.mediaRuntime.attach(session: mediaSession, contactID: contactID)
        viewModel.mediaRuntime.updateConnectionState(.connected)

        await viewModel.handleIncomingAudioPayload(
            "pcm-audio",
            channelID: "channel-1",
            fromUserID: "peer-user",
            fromDeviceID: "peer-device",
            contactID: contactID,
            incomingAudioTransport: .directQuic
        )
        await viewModel.handleIncomingAudioPayload(
            "pcm-audio",
            channelID: "channel-1",
            fromUserID: "peer-user",
            fromDeviceID: "peer-device",
            contactID: contactID,
            incomingAudioTransport: .mediaRelayPacket
        )
        await viewModel.handleIncomingAudioPayload(
