        #expect(config.supportsProjectionEpochs == true)
        #expect(config.supportsRuntimeQuicControl == true)
        #expect(config.supportsRuntimeTlsControl == true)
        #expect(config.runtimeControl?.preference == [
            .runtimeQuicControl,
            .runtimeTlsControl,
            .runtimeHttpRequest,
        ])
        #expect(
            config.runtimeControl?.quic
                == TurboRuntimeQuicControlConfig(
                    supported: true,
                    endpoint: "api.beepbeep.to:4433",
                    alpn: "beep-runtime-control-v1",
                    migrationEnabled: true
                )
        )
        #expect(
            config.runtimeControl?.tls
                == TurboRuntimeTlsControlConfig(
                    supported: true,
                    endpoint: "api.beepbeep.to:443"
                )
        )
        #expect(
            config.runtimeControl?.http
                == TurboRuntimeHttpControlConfig(
                    supported: true,
                    endpoint: "https://api.beepbeep.to"
                )
        )
        #expect(
            config.directQuicPolicy
                == TurboDirectQuicPolicy(
                    stunServers: [
                        TurboDirectQuicStunServer(host: "stun1.example.com", port: 3478),
                        TurboDirectQuicStunServer(host: "stun2.example.com", port: nil),
                    ],
                    stunProviders: [
                        TurboDirectQuicStunProvider(
                            name: "cloudflare",
                            enabled: true,
                            servers: [
                                TurboDirectQuicStunServer(host: "stun.cloudflare.com", port: 3478),
                            ]
                        ),
                        TurboDirectQuicStunProvider(
                            name: "google",
                            enabled: false,
                            servers: [
                                TurboDirectQuicStunServer(host: "stun.l.google.com", port: 19302),
                            ]
                        ),
                    ],
                    turnEnabled: true,
                    turnProvider: "cloudflare",
                    turnPolicyPath: "/v1/direct-quic/ice-servers",
                    turnCredentialTtlSeconds: 3600,
                    transportExperimentBucket: "cloudflare-turn-v1",
                    promotionTimeoutMs: 2500,
                    retryBackoffMs: 15000
                )
        )
        #expect(config.directQuicPolicy?.effectiveStunServers == [
            TurboDirectQuicStunServer(host: "stun.cloudflare.com", port: 3478),
        ])
        #expect(config.directQuicPolicy?.enabledStunProviderNames == ["cloudflare"])
    }

