    @Test func directQuicOfferEnvelopeRoundTripsTypedPayload() throws {
        let candidate = TurboDirectQuicCandidate(
            foundation: "host-a",
            component: "rtp",
            transport: "udp",
            priority: 100,
            kind: .host,
            address: "203.0.113.10",
            port: 4433,
