            _ = try VoicePacketV1Codec.decode(Data(repeating: 0, count: 32))
        }

        var encoded = VoicePacketV1Codec.encode(
            try VoicePacketV1(frameIndex: 0, opusPayload: Data([1, 2, 3]))
