        #expect(gapRecovery.plcRecoveryCount == 1)
        #expect(gapRecovery.fecRecoveryCount == 0)
        #expect(gapRecovery.adaptiveCushionIncreased)

        let late = try insert(1, nowNanoseconds: 1_060_000_000)
        #expect(late.lateDropCount == 1)
    }

