        )
        TurboDirectPathDebugOverride.setTransmitStartupPolicy(.appleGated)
        defer {
            if let previousPolicy {
                UserDefaults.standard.set(
                    previousPolicy,
                    forKey: TurboDirectPathDebugOverride.transmitStartupPolicyStorageKey
                )
