            )
        )
        #expect(
            viewModel.diagnosticsTranscript.contains(
                "Starting app-managed foreground receive playback fallback"
            )
        )
        #expect(
            viewModel.diagnosticsTranscript.contains(
                "Flushing buffered foreground receive audio through app-managed playback fallback"
            )
        )
    }

