            "fresh-packet-after-gap",
            "fresh-relay-packet",
        ])
        #expect(
            !viewModel.diagnostics.entries.contains {
                $0.message == "Dropped incoming audio after receive epoch changed"
                    && $0.metadata["incomingTransport"] == "media-relay-packet"
            }
        )
    }

